import React, { useEffect, useState } from 'react'
import { pondService, environmentLogService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/technician/technician-layout.css'
import '../../styles/technician/technician-thresholds.css'

const emptyThresholds = {
	minPh: '',
	maxPh: '',
	minTemp: '',
	maxTemp: '',
	minSalinity: '',
	maxSalinity: '',
	minOxygen: '',
	maxOxygen: '',
	minTurbidity: '',
	maxTurbidity: '',
}

const metricDefinitions = [
	{
		key: 'temperature',
		label: 'Nhiệt độ nước',
		unit: '°C',
		icon: '🌡️',
		minKey: 'minTemp',
		maxKey: 'maxTemp',
		defaultMin: 20,
		defaultMax: 35,
		precision: 1,
	},
	{
		key: 'ph',
		label: 'Độ pH',
		unit: 'pH',
		icon: 'pH',
		minKey: 'minPh',
		maxKey: 'maxPh',
		defaultMin: 6.5,
		defaultMax: 8.5,
		precision: 1,
	},
	{
		key: 'salinity',
		label: 'Độ mặn',
		unit: 'ppt',
		icon: '🧂',
		minKey: 'minSalinity',
		maxKey: 'maxSalinity',
		defaultMin: 10,
		defaultMax: 20,
		precision: 1,
	},
	{
		key: 'oxygen',
		label: 'Oxy hòa tan (DO)',
		unit: 'mg/L',
		icon: 'DO',
		minKey: 'minOxygen',
		maxKey: 'maxOxygen',
		defaultMin: 6,
		defaultMax: 8,
		precision: 1,
	},
	{
		key: 'turbidity',
		label: 'Độ đục',
		unit: 'NTU',
		icon: '💧',
		minKey: 'minTurbidity',
		maxKey: 'maxTurbidity',
		defaultMin: 0,
		defaultMax: 20,
		precision: 1,
	},
]

const clamp = (value, min, max) => Math.min(Math.max(value, min), max)

const toNumber = (value) => {
	const parsed = Number(value)
	return Number.isFinite(parsed) ? parsed : null
}

const formatValue = (value, precision = 1) => {
	if (!Number.isFinite(Number(value))) return '--'
	return Number(value).toFixed(precision)
}

const formatDateTime = (raw) => {
	if (!raw) return '--'
	const date = new Date(raw)
	if (Number.isNaN(date.getTime())) return '--'
	return date.toLocaleString('vi-VN', {
		day: '2-digit',
		month: '2-digit',
		year: 'numeric',
		hour: '2-digit',
		minute: '2-digit',
	})
}

const getMetricStatus = (current, minValue, maxValue) => {
	if (current == null) return 'no-data'
	if (minValue != null && current < minValue) return 'low'
	if (maxValue != null && current > maxValue) return 'high'
	return 'ok'
}

const getBarFill = (current, minValue, maxValue, defaultMin, defaultMax) => {
	if (current == null) return 0
	const start = minValue ?? defaultMin
	const end = maxValue ?? defaultMax
	const span = end - start || 1
	return clamp(((current - start) / span) * 100, 0, 100)
}

const buildMetricCards = (latestLog, thresholds) =>
	metricDefinitions.map((metric) => {
		const current = toNumber(latestLog?.[metric.key])
		const minValue = toNumber(thresholds[metric.minKey])
		const maxValue = toNumber(thresholds[metric.maxKey])
		const status = getMetricStatus(current, minValue, maxValue)

		return {
			...metric,
			current,
			minValue,
			maxValue,
			status,
			fill: getBarFill(current, minValue, maxValue, metric.defaultMin, metric.defaultMax),
		}
	})

const buildAlertItems = (metrics) => {
	const alerts = metrics.filter((metric) => metric.status === 'low' || metric.status === 'high')

	if (!alerts.length) {
		return [
			{
				key: 'all-clear',
				severity: 'ok',
				title: 'Mọi chỉ số đang ổn định',
				description: 'Các giá trị hiện tại chưa vượt ngưỡng cảnh báo đã thiết lập.',
			},
		]
	}

	return alerts.map((metric) => {
		const direction = metric.status === 'high' ? 'vượt ngưỡng tối đa' : 'thấp hơn ngưỡng tối thiểu'
		const thresholdValue = metric.status === 'high' ? metric.maxValue : metric.minValue
		const alertValue = metric.current != null ? `${formatValue(metric.current, metric.precision)} ${metric.unit}` : '--'
		const thresholdText = thresholdValue != null ? `${formatValue(thresholdValue, metric.precision)} ${metric.unit}` : '--'

		return {
			key: metric.key,
			severity: metric.status,
			title: `${metric.label} ${direction}`,
			description: `Giá trị hiện tại ${alertValue} so với ngưỡng ${thresholdText}.`,
		}
	})
}

const TechnicianThresholds = () => {
	const [ponds, setPonds] = useState([])
	const [selectedPondId, setSelectedPondId] = useState('')
	const [selectedPond, setSelectedPond] = useState(null)
	const [thresholds, setThresholds] = useState(emptyThresholds)
	const [latestLog, setLatestLog] = useState(null)
	const [recentLogs, setRecentLogs] = useState([])
	const [loading, setLoading] = useState(true)
	const [saving, setSaving] = useState(false)
	const [error, setError] = useState('')
	const [success, setSuccess] = useState('')

	useEffect(() => {
		fetchPonds()
	}, [])

	const loadPondData = async (pond) => {
		if (!pond?.pond_id) return

		setSelectedPondId(String(pond.pond_id))
		setSelectedPond(pond)

		try {
			const [thresholdRes, logsRes] = await Promise.all([
				environmentLogService.getThresholdsByPond(pond.pond_id),
				environmentLogService.getByPondId(pond.pond_id),
			])

			const thresholdData = thresholdRes?.data?.data
			if (thresholdData) {
				setThresholds({
					minPh: thresholdData.min_ph ?? '',
					maxPh: thresholdData.max_ph ?? '',
					minTemp: thresholdData.min_temp ?? '',
					maxTemp: thresholdData.max_temp ?? '',
					minSalinity: thresholdData.min_salinity ?? '',
					maxSalinity: thresholdData.max_salinity ?? '',
					minOxygen: thresholdData.min_oxygen ?? '',
					maxOxygen: thresholdData.max_oxygen ?? '',
					minTurbidity: thresholdData.min_turbidity ?? '',
					maxTurbidity: thresholdData.max_turbidity ?? '',
				})
			} else {
				setThresholds(emptyThresholds)
			}

			const logs = logsRes?.data?.data || []
			const sortedLogs = [...logs].sort(
				(a, b) =>
					new Date(b.recorded_at || b.created_at || b.logged_at || 0).getTime() -
					new Date(a.recorded_at || a.created_at || a.logged_at || 0).getTime()
			)

			setRecentLogs(sortedLogs.slice(0, 8))
			setLatestLog(sortedLogs[0] || null)
			setError('')
		} catch (err) {
			setThresholds(emptyThresholds)
			setRecentLogs([])
			setLatestLog(null)
			setError(err?.response?.data?.message || 'Không tải được dữ liệu ao')
		}
	}

	const fetchPonds = async () => {
		try {
			setLoading(true)
			const res = await pondService.getAllPonds()
			const pondsList = res?.data?.data || []
			setPonds(pondsList)

			if (pondsList.length > 0) {
				await loadPondData(pondsList[0])
			}
		} catch (err) {
			setError(err?.response?.data?.message || 'Không tải được danh sách ao')
		} finally {
			setLoading(false)
		}
	}

	const handlePondChange = async (pondId) => {
		const pond = ponds.find((item) => String(item.pond_id) === String(pondId))
		setSuccess('')
		if (pond) {
			await loadPondData(pond)
		}
	}

	const handleChange = (field, value) => {
		setThresholds((prev) => ({
			...prev,
			[field]: value === '' ? '' : Number(value),
		}))
	}

	const handleSubmit = async (event) => {
		event.preventDefault()
		if (!selectedPondId) {
			setError('Vui lòng chọn ao')
			return
		}

		try {
			setSaving(true)
			setError('')
			setSuccess('')

			if (thresholds.minPh && thresholds.maxPh && thresholds.minPh > thresholds.maxPh) {
				setError('pH: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minTemp && thresholds.maxTemp && thresholds.minTemp > thresholds.maxTemp) {
				setError('Nhiệt độ: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minSalinity && thresholds.maxSalinity && thresholds.minSalinity > thresholds.maxSalinity) {
				setError('Độ mặn: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minOxygen && thresholds.maxOxygen && thresholds.minOxygen > thresholds.maxOxygen) {
				setError('Oxy: Min phải nhỏ hơn Max')
				return
			}
			if (thresholds.minTurbidity && thresholds.maxTurbidity && thresholds.minTurbidity > thresholds.maxTurbidity) {
				setError('Độ đục: Min phải nhỏ hơn Max')
				return
			}

			const payload = {
				minPh: thresholds.minPh || null,
				maxPh: thresholds.maxPh || null,
				minTemp: thresholds.minTemp || null,
				maxTemp: thresholds.maxTemp || null,
				minSalinity: thresholds.minSalinity || null,
				maxSalinity: thresholds.maxSalinity || null,
				minOxygen: thresholds.minOxygen || null,
				maxOxygen: thresholds.maxOxygen || null,
				minTurbidity: thresholds.minTurbidity || null,
				maxTurbidity: thresholds.maxTurbidity || null,
			}

			await environmentLogService.setThresholdsByPond(selectedPondId, payload)
			await loadPondData(selectedPond || ponds.find((item) => String(item.pond_id) === String(selectedPondId)))
			setSuccess('Đã lưu cấu hình ngưỡng thành công')
			setTimeout(() => setSuccess(''), 3000)
		} catch (err) {
			setError(err?.response?.data?.message || 'Không lưu được ngưỡng cảnh báo')
		} finally {
			setSaving(false)
		}
	}

	const metricCards = buildMetricCards(latestLog, thresholds)
	const alertItems = buildAlertItems(metricCards)
	const lastUpdated = formatDateTime(latestLog?.recorded_at || latestLog?.created_at || latestLog?.logged_at)
	const currentStatus = metricCards.some((metric) => metric.status === 'low' || metric.status === 'high')
		? 'Cần chú ý'
		: latestLog
			? 'Bình thường'
			: 'Chưa có dữ liệu'

	if (loading) {
		return (
			<div className="dashboard technician-page-shell technician-thresholds-page">
				<div className="technician-thresholds__loading card">
					<p>Đang tải dữ liệu ngưỡng...</p>
				</div>
			</div>
		)
	}

	return (
		<div className="dashboard technician-page-shell technician-thresholds-page">
			{error && <div className="alert alert-danger technician-thresholds__alert">{error}</div>}
			{success && <div className="alert alert-success technician-thresholds__alert">{success}</div>}

			<section className="technician-thresholds__hero">
				<div>
					<p className="technician-thresholds__eyebrow">Thiết lập ngưỡng môi trường</p>
					<h1>Thiết lập ngưỡng môi trường</h1>
					<p>Cấu hình ngưỡng cảnh báo cho từng ao nuôi theo dữ liệu đo thực tế và cập nhật gần nhất.</p>
				</div>
				<button
					type="submit"
					form="technician-threshold-form"
					className="technician-thresholds__save-btn"
					disabled={saving || !selectedPondId}
				>
					{saving ? 'Đang lưu...' : 'Lưu cấu hình'}
				</button>
			</section>

			<section className="technician-thresholds__toolbar">
				<div className="technician-thresholds__selector">
					<label htmlFor="pond-select">Chọn ao nuôi</label>
					<select id="pond-select" value={selectedPondId} onChange={(e) => handlePondChange(e.target.value)}>
						{ponds.map((pond) => (
							<option key={pond.pond_id} value={pond.pond_id}>
								{pond.pond_code} - {pond.pond_name}
							</option>
						))}
					</select>
				</div>
				<div className="technician-thresholds__meta">
					<span className={`technician-thresholds__badge technician-thresholds__badge--${currentStatus === 'Bình thường' ? 'ok' : currentStatus === 'Cần chú ý' ? 'warning' : 'neutral'}`}>
						{currentStatus}
					</span>
					<span className="technician-thresholds__badge technician-thresholds__badge--live">Live</span>
					<span className="technician-thresholds__meta-text">Lần cập nhật gần nhất: {lastUpdated}</span>
				</div>
			</section>

			<div className="technician-thresholds__grid">
				<form id="technician-threshold-form" className="technician-thresholds__main" onSubmit={handleSubmit}>
					<div className="technician-thresholds__metrics-grid">
						{metricCards.map((metric) => {
							const statusLabel =
								metric.status === 'low'
									? 'Dưới ngưỡng'
									: metric.status === 'high'
										? 'Vượt ngưỡng'
										: metric.status === 'ok'
											? 'Trong ngưỡng'
											: 'Chưa có dữ liệu'
							const accentClass =
								metric.status === 'low'
									? 'threshold-card--low'
									: metric.status === 'high'
										? 'threshold-card--high'
										: metric.status === 'ok'
											? 'threshold-card--ok'
											: 'threshold-card--neutral'

							return (
								<article key={metric.key} className={`threshold-card ${accentClass}`}>
									<div className="threshold-card__head">
										<div className="threshold-card__title-group">
											<span className="threshold-card__icon">{metric.icon}</span>
											<div>
												<h3>{metric.label}</h3>
												<p>Giá trị hiện tại</p>
											</div>
										</div>
										<div className="threshold-card__value-wrap">
											<strong>
												{formatValue(metric.current, metric.precision)} <span>{metric.unit}</span>
											</strong>
											<span className={`threshold-card__status threshold-card__status--${metric.status}`}>
												{statusLabel}
											</span>
										</div>
									</div>

									<div className="threshold-card__bar">
										<div className="threshold-card__bar-track" />
										<div className="threshold-card__bar-fill" style={{ width: `${metric.fill}%` }} />
										<div className="threshold-card__bar-thumb" style={{ left: `${metric.fill}%` }} />
									</div>

									<div className="threshold-card__range-labels">
										<span>{metric.minValue != null ? formatValue(metric.minValue, metric.precision) : metric.defaultMin} {metric.unit}</span>
										<span>{metric.maxValue != null ? formatValue(metric.maxValue, metric.precision) : metric.defaultMax} {metric.unit}</span>
									</div>

									<div className="threshold-card__inputs">
										<div className="threshold-card__field">
											<label htmlFor={`min-${metric.key}`}>Ngưỡng tối thiểu</label>
											<div className="threshold-card__input-row">
												<input
													id={`min-${metric.key}`}
													type="number"
													step="0.1"
													value={thresholds[metric.minKey]}
													onChange={(e) => handleChange(metric.minKey, e.target.value)}
													placeholder={`Min ${metric.unit}`}
												/>
												<span>{metric.unit}</span>
											</div>
										</div>
										<div className="threshold-card__field">
											<label htmlFor={`max-${metric.key}`}>Ngưỡng tối đa</label>
											<div className="threshold-card__input-row">
												<input
													id={`max-${metric.key}`}
													type="number"
													step="0.1"
													value={thresholds[metric.maxKey]}
													onChange={(e) => handleChange(metric.maxKey, e.target.value)}
													placeholder={`Max ${metric.unit}`}
												/>
												<span>{metric.unit}</span>
											</div>
										</div>
									</div>
								</article>
							)
						})}
					</div>

					<section className="technician-thresholds__history-card">
						<div className="technician-thresholds__section-head">
							<div>
								<h2>Lịch sử dữ liệu gần đây</h2>
								<p>Dữ liệu ghi nhận gần nhất của ao đang chọn.</p>
							</div>
							<span>{recentLogs.length} bản ghi</span>
						</div>

						<div className="technician-thresholds__table-wrap">
							<table className="technician-thresholds__table">
								<thead>
									<tr>
										<th>Thời gian</th>
										<th>pH</th>
										<th>Nhiệt độ</th>
										<th>DO</th>
										<th>Độ mặn</th>
										<th>Độ đục</th>
									</tr>
								</thead>
								<tbody>
									{recentLogs.length > 0 ? (
										recentLogs.map((log, index) => (
											<tr key={`${log.environment_log_id || log.log_id || log.recorded_at || 'log'}-${index}`}>
												<td>{formatDateTime(log.recorded_at || log.created_at || log.logged_at)}</td>
												<td>{formatValue(log.ph, 1)} pH</td>
												<td>{formatValue(log.temperature, 1)}°C</td>
												<td>{formatValue(log.oxygen, 1)} mg/L</td>
												<td>{formatValue(log.salinity, 1)} ppt</td>
												<td>{formatValue(log.turbidity, 1)} NTU</td>
											</tr>
										))
									) : (
										<tr>
											<td colSpan="6" className="technician-thresholds__empty-row">
												Chưa có dữ liệu môi trường gần đây.
											</td>
										</tr>
									)}
								</tbody>
							</table>
						</div>
					</section>
				</form>

				<aside className="technician-thresholds__sidebar">
					<div className="technician-thresholds__panel technician-thresholds__pond-panel">
						<h2>Thông tin ao nuôi</h2>
						{selectedPond ? (
							<div className="technician-thresholds__pond-info">
								<div>
									<span>Ao</span>
									<strong>{selectedPond.pond_code} - {selectedPond.pond_name}</strong>
								</div>
								<div>
									<span>Diện tích</span>
									<strong>{selectedPond.area_m2 || '-'} m²</strong>
								</div>
								<div>
									<span>Trạng thái</span>
									<strong>{currentStatus}</strong>
								</div>
							</div>
						) : (
							<p className="technician-thresholds__empty">Chưa chọn ao nuôi.</p>
						)}
					</div>

					<div className="technician-thresholds__panel">
						<div className="technician-thresholds__section-head technician-thresholds__section-head--compact">
							<h2>Alert Preview Section</h2>
							<span>{alertItems.length}</span>
						</div>
						<ul className="technician-thresholds__alert-list">
							{alertItems.map((item) => (
								<li key={item.key} className={`technician-thresholds__alert-item technician-thresholds__alert-item--${item.severity}`}>
									<div className="technician-thresholds__alert-icon">
										{item.severity === 'high' ? '⚠️' : item.severity === 'low' ? '🚨' : 'ℹ️'}
									</div>
									<div>
										<strong>{item.title}</strong>
										<p>{item.description}</p>
									</div>
								</li>
							))}
						</ul>
					</div>
				</aside>
			</div>
		</div>
	)
}

export default TechnicianThresholds
